__inline
float euclid_dist_2(float *pt1,
                    float *pt2,
                    int    numdims)
{
    int i;
    float ans=0.0;

    for (i=0; i<numdims; i)
        ans += (pt1[i]-pt2[i]) * (pt1[i]-pt2[i]);

    return(ans);
}

int find_nearest_point(float  *pt,
                       int     nfeatures,
                       float **pts,
                       int     npts)
{
    int index, i;
    float min_dist=FLT_MAX;

    for (i=0; i<npts; i++) {
        float dist;
        dist = euclid_dist_2(pt, pts[i], nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index    = i;
        }
    }
    return(index);
}

kernel void kmeans_assign_cluster(
    global float *feature,
    global float *clusters,
    global int *membership,
    global int *partial_new_centers_len,
    global float *partial_new_centers,
    global float *delta,
    int npoints,
    int nclusters,
    int nfeatures,
    int nthreads)
{
    int i = get_global_id(0);
    int tid = get_global_id(1);

    if (i >= npoints || tid >= nthreads) return;

    int index = find_nearest_point(&feature[i * nfeatures],
                                   nfeatures,
                                   (float**)&clusters[0],
                                   nclusters);

    if (membership[i] != index) {
        delta[0] += 1.0f;
    }

    membership[i] = index;

    partial_new_centers_len[tid * nclusters + index]++;

    for (int j=0; j<nfeatures; j++) {
        partial_new_centers[tid * nclusters * nfeatures + index * nfeatures + j] += feature[i * nfeatures + j];
    }
}

kernel void kmeans_update_centers(
    global float *clusters,
    global float *new_centers,
    global int *new_centers_len,
    global float *partial_new_centers,
    global int *partial_new_centers_len,
    int nclusters,
    int nfeatures,
    int nthreads)
{
    int i = get_global_id(0);

    if (i >= nclusters) return;

    for (int j=0; j<nthreads; j++) {
        new_centers_len[i] += partial_new_centers_len[j * nclusters + i];
        partial_new_centers_len[j * nclusters + i] = 0;

        for (int k=0; k<nfeatures; k++) {
            new_centers[i * nfeatures + k] += partial_new_centers[j * nclusters * nfeatures + i * nfeatures + k];
            partial_new_centers[j * nclusters * nfeatures + i * nfeatures + k] = 0.0f;
        }
    }

    for (int j=0; j<nfeatures; j++) {
        if (new_centers_len[i] > 0)
            clusters[i * nfeatures + j] = new_centers[i * nfeatures + j] / new_centers_len[i];
        new_centers[i * nfeatures + j] = 0.0f;
    }
    new_centers_len[i] = 0;
}

float** kmeans_clustering_opencl(float **feature,
                          int     nfeatures,
                          int     npoints,
                          int     nclusters,
                          float   threshold,
                          int    *membership,
                          int     nthreads)
{
    int      i, j, k, n=0, index, loop=0;
    int     *new_centers_len;
    float   **new_centers;
    float   **clusters;
    float    delta;

    int     **partial_new_centers_len;
    float   ***partial_new_centers;

    clusters    = (float**) malloc(nclusters * sizeof(float*));
    clusters[0] = (float*)  malloc(nclusters * nfeatures * sizeof(float));
    for (i=1; i<nclusters; i++)
        clusters[i] = clusters[i-1] + nfeatures;

    for (i=0; i<nclusters; i++) {
        for (j=0; j<nfeatures; j++)
            clusters[i][j] = feature[n][j];
        n++;
    }

    for (i=0; i<npoints; i++)
        membership[i] = -1;

    new_centers_len = (int*) calloc(nclusters, sizeof(int));

    new_centers    = (float**) malloc(nclusters * sizeof(float*));
    new_centers[0] = (float*)  calloc(nclusters * nfeatures, sizeof(float));
    for (i=1; i<nclusters; i++)
        new_centers[i] = new_centers[i-1] + nfeatures;

    partial_new_centers_len    = (int**) malloc(nthreads * sizeof(int*));
    partial_new_centers_len[0] = (int*)  calloc(nthreads*nclusters, sizeof(int));
    for (i=1; i<nthreads; i++)
        partial_new_centers_len[i] = partial_new_centers_len[i-1]+nclusters;

    partial_new_centers    =(float***)malloc(nthreads * sizeof(float**));
    partial_new_centers[0] =(float**) malloc(nthreads*nclusters * sizeof(float*));
    for (i=1; i<nthreads; i++)
        partial_new_centers[i] = partial_new_centers[i-1] + nclusters;

    for (i=0; i<nthreads; i++)
    {
        for (j=0; j<nclusters; j++)
            partial_new_centers[i][j] = (float*)calloc(nfeatures, sizeof(float));
    }

    printf("num of threads = %d\n", nthreads);

    do {
        delta = 0.0;

        global float *feature_flat = (global float*)malloc(npoints * nfeatures * sizeof(float));
        global float *clusters_flat = (global float*)malloc(nclusters * nfeatures * sizeof(float));
        global int *membership_global = (global int*)malloc(npoints * sizeof(int));
        global int *partial_len_global = (global int*)malloc(nthreads * nclusters * sizeof(int));
        global float *partial_centers_global = (global float*)malloc(nthreads * nclusters * nfeatures * sizeof(float));
        global float *delta_global = (global float*)malloc(sizeof(float));

        for (i=0; i<npoints * nfeatures; i++)
            feature_flat[i] = feature[i / nfeatures][i % nfeatures];

        for (i=0; i<nclusters * nfeatures; i++)
            clusters_flat[i] = clusters[i / nfeatures][i % nfeatures];

        for (i=0; i<npoints; i++)
            membership_global[i] = membership[i];

        delta_global[0] = 0.0f;

        size_t global_size[2] = {npoints, nthreads};
        size_t local_size[2] = {1, 1};

        cl_kernel assign_kernel = clCreateKernel(program, "kmeans_assign_cluster");
        clSetKernelArg(assign_kernel, 0, sizeof(cl_mem), &feature_flat);
        clSetKernelArg(assign_kernel, 1, sizeof(cl_mem), &clusters_flat);
        clSetKernelArg(assign_kernel, 2, sizeof(cl_mem), &membership_global);
        clSetKernelArg(assign_kernel, 3, sizeof(cl_mem), &partial_len_global);
        clSetKernelArg(assign_kernel, 4, sizeof(cl_mem), &partial_centers_global);
        clSetKernelArg(assign_kernel, 5, sizeof(cl_mem), &delta_global);
        clSetKernelArg(assign_kernel, 6, sizeof(int), &npoints);
        clSetKernelArg(assign_kernel, 7, sizeof(int), &nclusters);
        clSetKernelArg(assign_kernel, 8, sizeof(int), &nfeatures);
        clSetKernelArg(assign_kernel, 9, sizeof(int), &nthreads);

        clEnqueueNDRangeKernel(queue, assign_kernel, 2, NULL, global_size, local_size);

        cl_kernel update_kernel = clCreateKernel(program, "kmeans_update_centers");
        clSetKernelArg(update_kernel, 0, sizeof(cl_mem), &clusters_flat);
        clSetKernelArg(update_kernel, 1, sizeof(cl_mem), &(float*)new_centers[0]);
        clSetKernelArg(update_kernel, 2, sizeof(cl_mem), &new_centers_len);
        clSetKernelArg(update_kernel, 3, sizeof(cl_mem), &partial_centers_global);
        clSetKernelArg(update_kernel, 4, sizeof(cl_mem), &partial_len_global);
        clSetKernelArg(update_kernel, 5, sizeof(int), &nclusters);
        clSetKernelArg(update_kernel, 6, sizeof(int), &nfeatures);
        clSetKernelArg(update_kernel, 7, sizeof(int), &nthreads);

        size_t update_global_size = nclusters;
        clEnqueueNDRangeKernel(queue, update_kernel, 1, NULL, &update_global_size, NULL);

        delta = delta_global[0];

        free(feature_flat);
        free(clusters_flat);
        free(membership_global);
        free(partial_len_global);
        free(partial_centers_global);
        free(delta_global);

    } while (delta > threshold && loop++ < 500);

    free(new_centers[0]);
    free(new_centers);
    free(new_centers_len);

    return clusters;
}

